class PhysicsEntity {
  private _velocityX: number = 0;
  private _velocityY: number = 0;
  private _velocityZ: number = 0;

  getVelocityX(): number { return this._velocityX; }
  setVelocityX(v: number): void { this._velocityX = v; }

  getVelocityY(): number { return this._velocityY; }
  setVelocityY(v: number): void { this._velocityY = v; }

  getVelocityZ(): number { return this._velocityZ; }
  setVelocityZ(v: number): void { this._velocityZ = v; }
}
